});

const withSession: MiddlewareHandler<AppBindings> = async (c, next) => {
  const auth = createAuth(c.env);
  const session = await auth.api.getSession({ headers: c.req.raw.headers });

  if (!session) {
    c.set("user", null);
    c.set("session", null);
    return next();
  }

  c.set("user", session.user);
  c.set("session", session.session);

  return next();
};

app.get('/:name', async (c) => {
  const name = c.req.param('name');
  if (!isPreviewName(name)) return c.text(`Unknown email preview: ${name}`, 404);

  const lng = c.req.query('lng') || appConfig.languages[0];
  const placeholders = c.req.query('placeholders') === '1';

  const { html } = await renderEmailPreview(name, { lng, placeholders });
  return c.html(html);
});

apiRoutes.post('/events/purge', async (c) => {
  const db = c.env.DB
  const settings = await getSettings(db)
  const service = new SecurityAuditService(db, settings)
  const body = await c.req.json().catch(() => ({})) as { daysToKeep?: number }
  const deleted = await service.purgeOldEvents(body.daysToKeep)
  return c.json({ success: true, deleted })
})

