header: SetHeaders = (name, value, options): void => {
  if (this.finalized) {
    this.#res = createResponseInstance((this.#res as Response).body, this.#res)
  }
  const headers = this.#res ? this.#res.headers : (this.#preparedHeaders ??= new Headers())
  if (value === undefined) {
    headers.delete(name)
  } else if (options?.append) {
    headers.append(name, value)
  } else {
    headers.set(name, value)
  }
}

for (const col of columns) {
  const [updated] = await db
    .update(columnTable)
    .set({ position: col.position })
    .where(
      and(eq(columnTable.id, col.id), eq(columnTable.projectId, projectId)),
    )
    .returning({ id: columnTable.id });

  if (!updated) {
    throw new HTTPException(400, {
      message: `Column ${col.id} does not belong to this project`,
    });
  }
}

